import json

# Load the article_metadata results from storage
metadata_path = var_functions.query_db:5
if isinstance(metadata_path, str) and metadata_path.endswith('.json'):
    with open(metadata_path, 'r') as f:
        article_metadata = json.load(f)
else:
    article_metadata = metadata_path

# Filter for Europe and date range 2010-2020
europe_articles = []
for article in article_metadata:
    if article['region'] == 'Europe':
        year = int(article['publication_date'][:4])
        if 2010 <= year <= 2020:
            europe_articles.append(article)

print('__RESULT__:')
print(json.dumps({
    'total_europe_articles_2010_2020': len(europe_articles),
    'sample_articles': europe_articles[:5]
}))

