import json
from collections import defaultdict
import re

# Load all articles file path
all_articles_path = locals()['var_functions.query_db:54']
if isinstance(all_articles_path, str) and '.json' in all_articles_path:
    with open(all_articles_path, 'r') as f:
        all_articles = json.load(f)
else:
    all_articles = all_articles_path

# Load Europe metadata file path  
europe_path = locals()['var_functions.query_db:37']
if isinstance(europe_path, str) and '.json' in europe_path:
    with open(europe_path, 'r') as f:
        europe_metadata = json.load(f)
else:
    europe_metadata = europe_path

# Create article lookup by article_id
articles_lookup = {article['article_id']: article for article in all_articles}

# Filter Europe metadata for 2010-2020 and match with articles
europe_articles_2010_2020 = []
for meta in europe_metadata:
    year = int(meta['publication_date'][:4])
    if 2010 <= year <= 2020:
        article_id = meta['article_id']
        if article_id in articles_lookup:
            article_data = articles_lookup[article_id]
            europe_articles_2010_2020.append({
                'article_id': article_id,
                'title': article_data['title'],
                'description': article_data['description'],
                'publication_date': meta['publication_date'],
                'year': year
            })

print('__RESULT__:')
print(json.dumps({
    'matched_articles_count': len(europe_articles_2010_2020),
    'sample_matched': europe_articles_2010_2020[:3] if europe_articles_2010_2020 else None
}))

